/**
 * Unit tests for session-state.ts (#1885 schema + helpers).
 *
 * Uses real temp filesystem — the lib's whole job is path math + atomic
 * write/read, and mocking fs would test the mocks, not the code.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, existsSync, readFileSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import {
  stateRootDir,
  repoSlugFromCwd,
  getStateFilePath,
  readSessionState,
  writeSessionStateAtomic,
  mergeSessionState,
  type SessionState,
} from '../../lib/session-state.js';

let workspace: string;

beforeEach(() => {
  workspace = mkdtempSync(join(tmpdir(), 'ork-session-state-'));
});

afterEach(() => {
  try {
    rmSync(workspace, { recursive: true, force: true });
  } catch {
    /* best-effort */
  }
});

describe('path helpers', () => {
  it('stateRootDir uses provided home', () => {
    expect(stateRootDir('/tmp/fake-home')).toBe('/tmp/fake-home/.claude/state/orchestkit');
  });

  it('repoSlugFromCwd is the basename', () => {
    expect(repoSlugFromCwd('/Users/yo/coding/platform')).toBe('platform');
    expect(repoSlugFromCwd('/x/y/orchestkit')).toBe('orchestkit');
  });

  it('getStateFilePath composes <root>/<repo>/<sid>.json', () => {
    const p = getStateFilePath('orchestkit', 'abc-123', '/h');
    expect(p).toBe('/h/.claude/state/orchestkit/orchestkit/abc-123.json');
  });
});

describe('readSessionState', () => {
  it('returns null when file is missing', () => {
    expect(readSessionState(join(workspace, 'nope.json'))).toBeNull();
  });

  it('returns null when file contains garbage JSON', () => {
    const p = join(workspace, 'corrupt.json');
    writeFileSync(p, '{not valid', 'utf8');
    expect(readSessionState(p)).toBeNull();
  });

  it('returns parsed object on valid JSON', () => {
    const p = join(workspace, 'ok.json');
    const state: SessionState = {
      repo: 'r',
      session_id: 's',
      started_at: '2026-05-20T00:00:00Z',
      last_heartbeat: '2026-05-20T00:01:00Z',
      status: 'running',
      last_commit: null,
      last_push: null,
      last_pr: null,
    };
    writeFileSync(p, JSON.stringify(state), 'utf8');
    expect(readSessionState(p)).toEqual(state);
  });
});

describe('writeSessionStateAtomic', () => {
  it('creates parent dirs and writes JSON', () => {
    const p = join(workspace, 'a', 'b', 'c', 'state.json');
    const s: SessionState = {
      repo: 'r',
      session_id: 's',
      started_at: 't',
      last_heartbeat: 't',
      status: 'running',
      last_commit: null,
      last_push: null,
      last_pr: null,
    };
    expect(writeSessionStateAtomic(p, s)).toBe(true);
    expect(existsSync(p)).toBe(true);
    expect(JSON.parse(readFileSync(p, 'utf8'))).toEqual(s);
  });

  it('does not leave behind a .tmp file on success', () => {
    const p = join(workspace, 'st.json');
    const s = {
      repo: 'r',
      session_id: 's',
      started_at: 't',
      last_heartbeat: 't',
      status: 'running',
      last_commit: null,
      last_push: null,
      last_pr: null,
    } satisfies SessionState;
    writeSessionStateAtomic(p, s);
    expect(existsSync(`${p}.tmp`)).toBe(false);
  });
});

describe('mergeSessionState', () => {
  const now = '2026-05-20T12:34:56Z';

  it('builds a fresh state when no existing state', () => {
    const out = mergeSessionState(null, {}, 'repo-x', 'sid-1', now);
    expect(out).toEqual({
      repo: 'repo-x',
      session_id: 'sid-1',
      started_at: now,
      last_heartbeat: now,
      status: 'running',
      last_commit: null,
      last_push: null,
      last_pr: null,
    });
  });

  it('preserves started_at across updates', () => {
    const existing: SessionState = {
      repo: 'r',
      session_id: 's',
      started_at: '2026-05-20T10:00:00Z',
      last_heartbeat: '2026-05-20T10:05:00Z',
      status: 'running',
      last_commit: null,
      last_push: null,
      last_pr: null,
    };
    const out = mergeSessionState(
      existing,
      { last_commit: { sha: 'abc', msg: 'x' } },
      'r',
      's',
      now,
    );
    expect(out.started_at).toBe('2026-05-20T10:00:00Z');
    expect(out.last_heartbeat).toBe(now);
    expect(out.last_commit).toEqual({ sha: 'abc', msg: 'x' });
  });

  it('always bumps last_heartbeat on merge', () => {
    const existing = mergeSessionState(null, {}, 'r', 's', '2026-05-20T10:00:00Z');
    const merged = mergeSessionState(existing, { status: 'completed' }, 'r', 's', '2026-05-20T11:00:00Z');
    expect(merged.last_heartbeat).toBe('2026-05-20T11:00:00Z');
    expect(merged.status).toBe('completed');
  });
});
